async (params, browser) => {
  // Open random article
  await browser.open('https://en.wikipedia.org/wiki/Special:Random')

  // Wait for article to load
  await browser.waitForSelector('#firstHeading, h1', 15000)

  // Let page render
  await browser.wait(1500)

  // Scroll to load content
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1000)

  // Extract random article
  const article_data = await browser.evaluate(`const titleEl = document.querySelector('#firstHeading, h1'); const content = document.querySelector('#mw-content-text .mw-parser-output'); const paragraphs = content ? content.querySelectorAll(':scope > p') : []; let summary = ''; for (let i = 0; i < Math.min(paragraphs.length, 3); i++) { const text = paragraphs[i].textContent.trim(); if (text.length > 50) { summary += text + ' '; } } const infobox = {}; const infoboxEl = document.querySelector('.infobox, .vcard'); if (infoboxEl) { const rows = infoboxEl.querySelectorAll('tr'); rows.forEach(function(row) { const th = row.querySelector('th'); const td = row.querySelector('td'); if (th && td) { infobox[th.textContent.trim()] = td.textContent.trim().substring(0, 200); } }); } const categories = []; const catLinks = document.querySelectorAll('#catlinks li a, #mw-normal-catlinks li a'); catLinks.forEach(function(a) { categories.push(a.textContent.trim()); }); const images = []; const imgEls = content ? content.querySelectorAll('img[src*="upload.wikimedia"]') : []; imgEls.forEach(function(img) { const src = img.getAttribute('src'); if (src && src.includes('upload.wikimedia') && !images.includes(src)) images.push(src.startsWith('//') ? 'https:' + src : src); }); return { title: titleEl ? titleEl.textContent.trim() : '', summary: summary.trim().substring(0, 2000), infobox: infobox, categories: categories.slice(0, 10), images: images.slice(0, 3), url: window.location.href }`)

  return article_data
}
